// Register a new user
function custom_user_registration($username, $email, $password) {
    if (username_exists($username)) {
        return 'Username already exists.';
    }
    if (!is_email($email)) {
        return 'Invalid email address.';
    }
    if (email_exists($email)) {
        return 'Email already registered.';
    }

    $user_id = wp_create_user($username, $password, $email);
    if (!is_wp_error($user_id)) {
        return 'User registered successfully.';
    } else {
        return 'Error registering user: ' . $user_id->get_error_message();
    }
}

// Login a user
function custom_user_login($username, $password) {
    $user = get_user_by('login', $username);
    if (!$user || !wp_check_password($password, $user->user_pass, $user->ID)) {
        return 'Invalid username or password.';
    }

    wp_set_current_user($user->ID);
    wp_set_auth_cookie($user->ID);

    do_action('wp_login', $user->user_login);

    return 'User logged in successfully.';
}

// Add shortcode for registration
function custom_registration_shortcode() {
    if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['register'])) {
        $username = sanitize_user($_POST['username']);
        $email = sanitize_email($_POST['email']);
        $password = $_POST['password'];

        $result = custom_user_registration($username, $email, $password);
        echo '<p>' . esc_html($result) . '</p>';
    }

    return '
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="email" name="email" placeholder="Email" required>
            <input type="password" name="password" placeholder="Password" required>
            <input type="submit" name="register" value="Register">
        </form>
    ';
}
add_shortcode('custom_registration', 'custom_registration_shortcode');

// Add shortcode for login
function custom_login_shortcode() {
    if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['login'])) {
        $username = sanitize_user($_POST['username']);
        $password = $_POST['password'];

        $result = custom_user_login($username, $password);
        echo '<p>' . esc_html($result) . '</p>';
    }

    return '
        <form method="post">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <input type="submit" name="login" value="Login">
        </form>
    ';
}
add_shortcode('custom_login', 'custom_login_shortcode');
